CREATE TABLE fuzzy_test (id INT PRIMARY KEY, data VARCHAR(255) NOT NULL, numeric_value INT, wide_text VARCHAR(255) CHARACTER SET utf8);
INSERT INTO fuzzy_test VALUES (1, 'abc123', 100, 'Hello World!'), (2, 'def456', 200, 'Привет мир!'), (3, NULL, 300, 'こんにちは世界'), (4, '', 400, NULL);
SELECT id, REGEXP_MATCH('^[a-z]+([0-9]+)', data) AS matched_substring FROM fuzzy_test WHERE numeric_value LIKE '2%';
SELECT id, data, REGEXP_MATCH('.*[a-z]{3}.*', data) AS is_match FROM fuzzy_test WHERE REGEXP_MATCH('^$', data) IS NULL;
SELECT id, data, numeric_value FROM fuzzy_test WHERE data LIKE REGEXP_MATCH('[0-9]+', data) OR REGEXP_MATCH('Hello', wide_text) IS NOT NULL;
SELECT id, data, REGEXP_MATCH('([^ ]+)', data) AS first_word FROM fuzzy_test WHERE data IS NOT NULL AND wide_text IS NULL GROUP BY first_word HAVING COUNT(*) > 1;
SELECT id, data, numeric_value FROM fuzzy_test WHERE REGEXP_MATCH('^abc', data) AND (SELECT COUNT(*) FROM fuzzy_test WHERE numeric_value > 150) > 1;
SELECT a.id, a.data, REGEXP_MATCH(CONCAT('%', a.data, '%'), b.data) AS pattern_match FROM fuzzy_test a JOIN fuzzy_test b ON a.numeric_value = b.numeric_value WHERE a.data != b.data AND b.data LIKE 'def%';
CREATE TEMPORARY TABLE temp_test AS SELECT id, data, REGEXP_MATCH('[0-9]+', data) FROM fuzzy_test WHERE data IS NOT NULL;
SELECT id, GROUP_CONCAT(REGEXP_MATCH('([a-z]+)', data)) AS all_matches FROM fuzzy_test GROUP BY id HAVING COUNT(data) < 3;
